-- Create function dbo.PIM_GET_COLUMN_LIST
PRINT N'Create function dbo.PIM_GET_COLUMN_LIST'
GO
-- --------------------------------------------------------------------------------
-- SQL Server function to return the list of non-PK columns in the specified table.
-- 
-- Input Parameters
-- ----------------
-- SchemaName: Database schema of the history table of interest.
-- TableName:  Name of the history table of interest.
-- 
-- Output Parameters
-- -----------------
-- ColumnLst: The comma-separated list of non-PK columns for the specified table.
-- 
-- Author        Date         Comment
-- ------------  -----------  -----------------------------------------------------
-- Doug Filteau  2025-Apr-04  Initial version.
-- --------------------------------------------------------------------------------

CREATE FUNCTION [dbo].[PIM_GET_COLUMN_LIST] (@prmSchemaName nvarchar(128) = 'dbo', @prmTableName nvarchar(128), @prmPKColName NVARCHAR(128))
RETURNS nvarchar(max)
AS
  BEGIN
  DECLARE @ColumnLst nvarchar(max);
  
  SELECT   @ColumnLst = COALESCE(@ColumnLst + ', ', '') + COLUMN_NAME
  FROM     information_schema.columns
  WHERE    TABLE_SCHEMA = @prmSchemaName
       AND TABLE_NAME   = @prmTableName
       AND COLUMN_NAME <> @prmPKColName
  ORDER BY ORDINAL_POSITION
  
  RETURN @ColumnLst
  END

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

-- Create function dbo.PIM_GET_PK_COLUMN
PRINT N'Create function dbo.PIM_GET_PK_COLUMN'
GO
-- --------------------------------------------------------------------------------
-- SQL Server function to return the primary key column of the specified table
-- 
-- Input Parameters
-- ----------------
-- SchemaName: Database schema of the history table of interest.
-- TableName:  Name of the history table of interest.
-- 
-- Output Parameters
-- -----------------
-- PKColNm: The name of the primary key column for the table.
-- 
-- Author        Date         Comment
-- ------------  -----------  -----------------------------------------------------
-- Doug Filteau  2025-Feb-27  Initial version.
-- --------------------------------------------------------------------------------

CREATE FUNCTION [dbo].[PIM_GET_PK_COLUMN] (@SchemaName nvarchar(128), @TableName nvarchar(128))
RETURNS nvarchar(128)
AS
  BEGIN
  DECLARE @Result   nvarchar(128)

  -- Retrieve the name of the primary key column from the specified table.
  SET @Result = (SELECT COLUMN_NAME
                 FROM   information_schema.key_column_usage
                 WHERE  OBJECTPROPERTY(OBJECT_ID(CONSTRAINT_SCHEMA + '.' + QUOTENAME(CONSTRAINT_NAME)), 'IsPrimaryKey') = 1
                    AND TABLE_SCHEMA = @SchemaName
                    AND TABLE_NAME   = @TableName)

  RETURN @Result 
  END

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

-- Create procedure dbo.PIM_DELETION_HISTORY
PRINT N'Create procedure dbo.PIM_DELETION_HISTORY'
GO
-- ********************************************************************************
-- Stored procedure to preserve the user that deleted the record in the history 
-- table.
-- 
-- Parameter     Description
-- ------------  ------------------------------------------------------------------
-- prmUserID     The user ID of the user that deleted the record.
-- prmHstSchema  The name of the database schema of the history table.
-- prmBizSchema  The name of the database schema of the business table.
-- prmBizTblNm   The name of the business table that is being operated upon.  This 
--               table must have a corresponding history table.
-- prmPKValue    The value of the primary key of the record in the business table 
--               that is being deleted. 
-- 
-- . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . .
-- Author        Date         Comment
-- ------------  -----------  -----------------------------------------------------
-- Doug Filteau  2024-Sep-26  Original version.
-- Doug Filteau  2025-Mar-25  Further enhancement and debugging capability.
-- Doug Filteau  2025-Mar-28  Add row cloning to preserve original UserID.
-- Doug Filteau  2025-Aug-26  Added DROP statement.
-- ********************************************************************************

CREATE PROCEDURE [dbo].[PIM_DELETION_HISTORY] @prmUserID    nvarchar(30),
                                              @prmHstSchema nvarchar(128) = 'dbo', 
                                              @prmBizSchema nvarchar(128) = 'dbo', 
                                              @prmBizTblNm  nvarchar(128), 
                                              @prmPKValue   bigint,
                                              @modeDebug    bit = 0
AS
BEGIN
  SET XACT_ABORT ON;
  SET NOCOUNT ON;
  
  DECLARE @HstPKCol  nvarchar(128); -- Column name of the primary key of the history table.
  DECLARE @BizPKCol  nvarchar(128); -- Column name of the primary key of the business table.
  DECLARE @HstTblNm  nvarchar(128); -- Derived name of the history table.
  DECLARE @ColList   nvarchar(max); -- Non-PK column list of the history table.
  DECLARE @InsList   nvarchar(max); -- Non-PK column list of the values to be 
                                    -- instered into the history table.
  DECLARE @HstPKValu bigint;        -- Value of the newly cloned history row.
  DECLARE @RowCount  integer;       -- Count of rows with specified PK value.
  DECLARE @Msg       nvarchar(50);  -- Generic error message.
  DECLARE @qry       nvarchar(max); -- Dynamic query string.
  
  DECLARE @trancount int;
  SET @trancount = @@trancount;
  
  BEGIN TRY
  	IF @trancount = 0 
      BEGIN TRANSACTION PIM_DELETION_HISTORY
    ELSE
      SAVE TRANSACTION PIM_DELETION_HISTORY;
    	
    -- Initialize the name of the history table.
    IF @prmHstSchema = N'dbo'
      SET @HstTblNm = @prmBizTblNm + '_HIST'
    ELSE
      SET @HstTblNm = @prmBizTblNm;
      
    -- Determine the name of the primary key column in the history table.
    SET @HstPKCol = dbo.PIM_GET_PK_COLUMN (@prmHstSchema, @HstTblNm);
    
    -- Determine the name of the primary key column in the business table.
    SET @BizPKCol = dbo.PIM_GET_PK_COLUMN (@prmBizSchema, @prmBizTblNm);
        
    -- Delete the specified record.
    SET @qry = 'DELETE FROM [' + @prmBizSchema + '].[' + @prmBizTblNm + '] WHERE ' + @BizPKCol + ' = ' + CONVERT(nvarchar, @prmPKValue);
    
    -- If not in debug mode, execute the query.  Otherwise display the values of 
    -- the internal variables. 
    IF @modeDebug = 1
      BEGIN
      PRINT '@qry = ' + @qry;
      END
    ELSE
      BEGIN
      EXEC sp_executesql @qry;
      SELECT @RowCount = @@ROWCOUNT;
      -- If RowCount = 0, the record was not deleted.  Stop execution of the 
      -- stored procedure and return to the caller.
      IF @RowCount = 0
        BEGIN
        SET @Msg = 'Record for ' + @prmPKValue + 'in table ' + @prmBizSchema + '.' + @prmBizTblNm + + ' not deleted.';
        RAISERROR (@Msg, 16, 1) WITH NOWAIT;
        RETURN;
        END;
      END;
    
    -- Obtain the list of columns for the history record  
    SET @ColList = [dbo].[PIM_GET_COLUMN_LIST] (@prmHstSchema, @HstTblNm, @HstPKCol);
    
    -- Modify the column list to alter the columns specific to deletion.
    SET @InsList = STUFF(@ColList, CHARINDEX('EFFECTIVE_DATE_HIST, END_DATE_HIST, ', @ColList), LEN('EFFECTIVE_DATE_HIST, END_DATE_HIST, '), 'getutcdate(), getutcdate(), ');  -- Current dates for Effective/End dates
    SET @InsList = STUFF(@InsList, CHARINDEX('APP_LAST_UPDATE_USERID',               @InsList), LEN('APP_LAST_UPDATE_USERID'),               QUOTENAME(@prmUserID, ''''));     -- Userid requestiong the deletion.
    SET @InsList = STUFF(@InsList, CHARINDEX('APP_LAST_UPDATE_USER_DIRECTORY',       @InsList), LEN('APP_LAST_UPDATE_USER_DIRECTORY'),       QUOTENAME('DELETED',  ''''));     -- Indicates this is a deleted row.

    -- If in debug mode, display the values of the internal variables. 
    IF @modeDebug = 1
      BEGIN
      PRINT '@ColList = ' + @ColList;
      PRINT '@InsList = ' + @InsList;  
      END;
    
    -- Clone most recent history row for the specified business PK and populate 
    -- the END_DATE_HIST, APP_LAST_UPDATE_USERID, and APP_LAST_UPDATE_USER_DIRECTORY 
    -- columns of the newly created history row.
    SET @qry =        'WITH cte_Latest_Hist_Row (HIST_ID, BIZ_ID, RANK) AS ';
    SET @qry = @qry + '(SELECT ' + @HstPKCol + ', ' + @BizPKCol + ', RANK() OVER (PARTITION BY ' + @BizPKCol + ' ORDER BY END_DATE_HIST DESC) AS RANK FROM ' + @prmHstSchema + '.' + @HstTblNm + ') ';
    SET @qry = @qry + 'INSERT INTO ' + @prmHstSchema + '.' + @HstTblNm + ' (' + @ColList + ') ';
    SET @qry = @qry + 'SELECT ' + @InsList + ' ';
    SET @qry = @qry + 'FROM ' + @prmHstSchema + '.' + @HstTblNm + ' hst JOIN cte_Latest_Hist_Row cte ON ';
    SET @qry = @qry + 'cte.HIST_ID = hst.' + @HstPKCol + ' ';
    SET @qry = @qry + 'WHERE cte.RANK = 1 AND cte.BIZ_ID ' + ' = ' + CONVERT(nvarchar, @prmPKValue);
    
    -- If not in debug mode, execute the query.  Otherwise display the values of 
    -- the internal variables. 
    IF @modeDebug = 0
      BEGIN
      EXEC sp_executesql @qry;
      END
    ELSE
      BEGIN
      PRINT '@qry = ' + @qry;
      END;

    IF @trancount = 0
      COMMIT TRANSACTION
  END TRY
  
  BEGIN CATCH
    DECLARE @error INT, @message VARCHAR(4000), @xstate INT;
    SELECT @error = ERROR_NUMBER(), @message = ERROR_MESSAGE(), @xstate = XACT_STATE();
    IF (XACT_STATE()) = -1
      ROLLBACK;
    IF (XACT_STATE()) = 1 AND @trancount = 0
      ROLLBACK;
    IF (XACT_STATE()) = 1 AND @trancount > 0
      ROLLBACK TRANSACTION PIM_DELETION_HISTORY;
    
    RAISERROR ('PIM_DELETION_HISTORY: %d: %s', 16, 1, @error, @message) ;
  END CATCH
END;

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

-- Create view dbo.PIMS_PROPERTY_LITE_VW
PRINT N'Create view dbo.PIMS_PROPERTY_LITE_VW'
GO
CREATE VIEW [dbo].[PIMS_PROPERTY_LITE_VW] AS
SELECT PROP.PROPERTY_ID
     , PROP.BOUNDARY
     , PROP.LOCATION  
     , PROP.IS_OWNED
     , PROP.IS_RETIRED
     , CASE
         WHEN EXISTS (SELECT 1
                      FROM   PIMS_TAKE                      TAKE JOIN
                             PIMS_PROPERTY_ACQUISITION_FILE PRAF   ON PRAF.PROPERTY_ACQUISITION_FILE_ID = TAKE.PROPERTY_ACQUISITION_FILE_ID
                                                                  AND PRAF.PROPERTY_ID                  = PROP.PROPERTY_ID
                      WHERE  TAKE.IS_NEW_LAND_ACT       = 1
                         AND TAKE.TAKE_STATUS_TYPE_CODE = 'COMPLETE'
                         AND TAKE.LAND_ACT_TYPE_CODE   IN (N'Section 15', N'Section 16', N'Section 17', N'Section 66', N'NOI')) THEN CONVERT([bit],(1))
         WHEN EXISTS (SELECT 1
                      FROM   PIMS_TAKE                      TAKE JOIN
                             PIMS_PROPERTY_ACQUISITION_FILE PRAF   ON PRAF.PROPERTY_ACQUISITION_FILE_ID = TAKE.PROPERTY_ACQUISITION_FILE_ID
                                                                  AND PRAF.PROPERTY_ID                  = PROP.PROPERTY_ID
                      WHERE  TAKE.IS_NEW_INTEREST_IN_SRW = 1
                         AND TAKE.TAKE_STATUS_TYPE_CODE  = N'COMPLETE') THEN CONVERT([bit],(1))
         WHEN EXISTS (SELECT 1
                      FROM   PIMS_TAKE                      TAKE JOIN
                             PIMS_PROPERTY_ACQUISITION_FILE PRAF   ON PRAF.PROPERTY_ACQUISITION_FILE_ID = TAKE.PROPERTY_ACQUISITION_FILE_ID
                                                                  AND PRAF.PROPERTY_ID                  = PROP.PROPERTY_ID
                      WHERE  TAKE.IS_NEW_LICENSE_TO_CONSTRUCT = 1
                         AND TAKE.TAKE_STATUS_TYPE_CODE       = N'COMPLETE') THEN CONVERT([bit],(1))
         WHEN EXISTS (SELECT 1
                      FROM   PIMS_TAKE                      TAKE JOIN
                             PIMS_PROPERTY_ACQUISITION_FILE PRAF   ON PRAF.PROPERTY_ACQUISITION_FILE_ID = TAKE.PROPERTY_ACQUISITION_FILE_ID
                                                                  AND PRAF.PROPERTY_ID                  = PROP.PROPERTY_ID
                      WHERE  IS_ACTIVE_LEASE       = 1
                         AND TAKE_STATUS_TYPE_CODE = N'COMPLETE') THEN CONVERT([bit],(1))
         ELSE CONVERT([bit],(0))
         END AS IS_OTHER_INTEREST
     , IIF(EXISTS (SELECT 1
                   FROM   PIMS_DISPOSITION_FILE_PROPERTY DFPR JOIN
                          PIMS_DISPOSITION_FILE          DISP   ON DISP.DISPOSITION_FILE_ID = DFPR.DISPOSITION_FILE_ID
                                                               AND DFPR.PROPERTY_ID         = PROP.PROPERTY_ID
                   WHERE  DISP.DISPOSITION_FILE_STATUS_TYPE_CODE = N'COMPLETE'), CONVERT([bit],(1)), CONVERT([bit],(0))) AS IS_DISPOSED
     , IIF(EXISTS (SELECT 1
                   FROM   PIMS_PROPERTY_ACQUISITION_FILE PRAF JOIN
                          PIMS_ACQUISITION_FILE          ACQF   ON ACQF.ACQUISITION_FILE_ID = PRAF.ACQUISITION_FILE_ID
                                                               AND PRAF.PROPERTY_ID         = PROP.PROPERTY_ID
                   WHERE  ACQF.ACQUISITION_FILE_STATUS_TYPE_CODE IN (N'DRAFT', N'ACTIVE')), CONVERT([bit],(1)), CONVERT([bit],(0))) AS HAS_ACTIVE_ACQUISITION_FILE
     , IIF(EXISTS (SELECT 1
                   FROM   PIMS_PROPERTY_RESEARCH_FILE PRSF JOIN
                          PIMS_RESEARCH_FILE          RSHF   ON RSHF.RESEARCH_FILE_ID = PRSF.RESEARCH_FILE_ID
                                                            AND PRSF.PROPERTY_ID      = PROP.PROPERTY_ID
                   WHERE  RSHF.RESEARCH_FILE_STATUS_TYPE_CODE = N'ACTIVE'), CONVERT([bit],(1)), CONVERT([bit],(0)))  AS HAS_ACTIVE_RESEARCH_FILE
FROM   PIMS_PROPERTY PROP
WHERE  PROP.LOCATION IS NOT NULL

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

