-- Create trigger dbo.PIMS_PIMPRS_I_S_U_TR
PRINT N'Create trigger dbo.PIMS_PIMPRS_I_S_U_TR'
GO
CREATE TRIGGER [dbo].[PIMS_PIMPRS_I_S_U_TR] ON PIMS_PROP_IMPRVMNT_STATUS_TYPE INSTEAD OF UPDATE AS
SET NOCOUNT ON
BEGIN TRY
  IF NOT EXISTS(SELECT * FROM deleted) 
    RETURN;

  -- validate concurrency control
  if exists (select 1 from inserted, deleted where inserted.CONCURRENCY_CONTROL_NUMBER != deleted.CONCURRENCY_CONTROL_NUMBER+1 AND inserted.PROP_IMPRVMNT_STATUS_TYPE_CODE = deleted.PROP_IMPRVMNT_STATUS_TYPE_CODE)
    raiserror('CONCURRENCY FAILURE.',16,1)


  -- update statement
  update PIMS_PROP_IMPRVMNT_STATUS_TYPE
    set "PROP_IMPRVMNT_STATUS_TYPE_CODE" = inserted."PROP_IMPRVMNT_STATUS_TYPE_CODE",
      "DESCRIPTION" = inserted."DESCRIPTION",
      "IS_DISABLED" = inserted."IS_DISABLED",
      "DISPLAY_ORDER" = inserted."DISPLAY_ORDER",
      "CONCURRENCY_CONTROL_NUMBER" = inserted."CONCURRENCY_CONTROL_NUMBER"
    , DB_LAST_UPDATE_TIMESTAMP = getutcdate()
    , DB_LAST_UPDATE_USERID = user_name()
    from PIMS_PROP_IMPRVMNT_STATUS_TYPE
    inner join inserted
    on (PIMS_PROP_IMPRVMNT_STATUS_TYPE.PROP_IMPRVMNT_STATUS_TYPE_CODE = inserted.PROP_IMPRVMNT_STATUS_TYPE_CODE);

END TRY
BEGIN CATCH
   IF @@trancount > 0 ROLLBACK TRANSACTION
   EXEC pims_error_handling
END CATCH;

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

